import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.http.ResponseEntity;
import org.springframework.security.core.context.SecurityContextHolder;
import org.springframework.web.bind.annotation.*;

@RestController
public class OrderController {
    
    @Autowired
    private OrderService orderService;

    @GetMapping("/orders/{orderId}")
    public ResponseEntity<Order> getOrderDetails(@PathVariable("orderId") Long orderId) {
        // assuming the user details are stored in security context by an authentication filter.
        String username = SecurityContextHolder.getContext().getAuthentication().getName();
        
        Order order = orderService.findByUsernameAndOrderId(username, orderId);
        
        if (order == null) {
            return ResponseEntity.notFound().build();
        } else {
            return ResponseEntity.ok(order);
        }
    }
}